const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');

const DATA_DIR = path.join(__dirname, '..', 'data');
const CDP_URL = 'http://127.0.0.1:9222';

// ----- helpers -----

const SYSTEM_MSG_PATTERNS = [
  /automatic reception will no longer intervene/i,
  /自动接待将不再触发/,
  /Marco大模型翻译/,
  /阿里国际Marco大模型翻译/,
  /买家有流失风险/,
  /Buyer has churn risk/,
  /一旦离开平台发生纠纷或欺诈/,
  /由于您介入该会话/,
  /Due to your intervention in this session/,
  /AI给您生成了一条回复建议/,
  /反馈/,
];

function isSystemMessage(text) {
  if (!text) return true;
  return SYSTEM_MSG_PATTERNS.some((p) => p.test(text));
}

function isRealContact(name, msg) {
  if (!name || name.length < 2) return false;
  // Filter UI labels and bots
  const skip = ['全部', '消息', 'Assistant Eva', '已折叠', '未读', '已读', '待回复', '待跟进'];
  if (skip.some((s) => name.includes(s))) return false;
  // Filter CSS/symbol noise
  if (/^[\.\#\@\{\}]/.test(name)) return false;
  if (name.length > 60) return false;
  return true;
}

function parseDaysAgo(timeStr) {
  if (!timeStr) return 99;
  if (timeStr.includes(':')) return 0; // today's time like "11:37"
  const m = timeStr.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);
  if (m) {
    const d = new Date(parseInt(m[1]), parseInt(m[2]) - 1, parseInt(m[3]));
    return Math.round((Date.now() - d.getTime()) / 86400000);
  }
  return 99;
}

// ----- main -----

(async () => {
  let browser;
  try {
    browser = await chromium.connectOverCDP(CDP_URL);
  } catch (e) {
    console.log('❌ CDP连接失败');
    process.exit(1);
  }

  const context = browser.contexts()[0];
  const page = await context.newPage();

  console.log('加载 onetalk...');
  await page.goto(
    'https://onetalk.alibaba.com/message/weblitePWA.htm?relevanceAccountId=285526143&from=xiaoman',
    { waitUntil: 'networkidle', timeout: 20000 }
  ).catch(() => {});
  await page.waitForTimeout(5000);

  // Scroll to load more contacts
  console.log('滚动加载...');
  for (let i = 0; i < 8; i++) {
    await page.evaluate(() => {
      const scrollers = document.querySelectorAll('[class*=scroll]');
      scrollers.forEach((s) => {
        s.scrollTop += 600;
      });
    }).catch(() => {});
    await page.waitForTimeout(500);
  }
  await page.waitForTimeout(2000);

  // Extract contacts from contact-item-container elements
  console.log('提取联系人...');
  const rawContacts = await page.evaluate(() => {
    const results = [];
    const items = document.querySelectorAll('.contact-item-container, [class*=contact-item]');

    for (const item of items) {
      const text = item.textContent?.trim() || '';
      if (!text || text.length < 10) continue;

      // Parse: name + time + [status] + message
      // Pattern: "...NameHH:MM[未读] msg..." or "...NameYYYY-M-D[已读] msg..."

      // Split on status marker
      const statusParts = text.split(/\[未读\]|\[已读\]/);
      if (statusParts.length < 2) continue;

      const nameTimePart = statusParts[0].trim();
      const msgPart = statusParts.slice(1).join('').trim();
      const isUnread = text.includes('[未读]');

      // Extract time from the end of nameTimePart
      const timeMatch = nameTimePart.match(/(\d{1,2}:\d{2}|\d{4}-\d{1,2}-\d{1,2})$/);
      if (!timeMatch) continue;

      const timeStr = timeMatch[1];
      // Name is everything before the time
      let name = nameTimePart.substring(0, timeMatch.index).trim();

      // Clean name: strip leading labels
      name = name.replace(/^[未读已读]+/, '').trim();

      // Fix doubled first character (DOM text merge artifact)
      // "BBrian Robert Ocholi" → "Brian Robert Ocholi"
      // "aamer ly" → "amer ly" (lowercase merge)
      if (name.length > 2) {
        const c0 = name[0];
        const c1 = name[1];
        if (c0 === c1 && /[A-Z]/.test(c0)) {
          name = name.substring(1);
        } else if (c0.toLowerCase() === c0 && c1 === c0) {
          // lowercase duplicated: "aamer" → "amer"
          name = name.substring(1);
        } else if (name.length > 3 && name[0].toLowerCase() === name[0] && name[1] === name[0] && /[A-Z]/.test(name[2])) {
          // "aamer ly" pattern: two lowercase dupes before a capital
          name = name.substring(1);
        }
      }

      // Skip if name looks invalid
      if (!name || name.length < 2 || name.length > 80) continue;

      results.push({ name, timeStr, isUnread, message: msgPart });
    }

    return results;
  });

  // Deduplicate by name
  const seen = new Set();
  const contacts = [];
  for (const c of rawContacts) {
    if (!isRealContact(c.name, c.message)) continue;
    if (seen.has(c.name.toLowerCase())) continue;
    seen.add(c.name.toLowerCase());
    contacts.push(c);
  }

  console.log(`原始: ${rawContacts.length} → 过滤后: ${contacts.length}人`);

  // Classify
  const now = Date.now();
  const classified = contacts.map((c) => {
    const daysAgo = parseDaysAgo(c.timeStr);
    const isSys = isSystemMessage(c.message);

    let priority, tier, reasons;
    if (isSys) {
      priority = 'P2'; tier = 'C'; reasons = ['系统消息'];
    } else if (c.isUnread) {
      priority = 'P0'; tier = 'S'; reasons = ['有未读消息'];
    } else if (daysAgo <= 1) {
      priority = 'P0'; tier = 'A'; reasons = ['今日活跃'];
    } else if (daysAgo <= 3) {
      priority = 'P1'; tier = 'A'; reasons = ['3天内活跃'];
    } else if (daysAgo <= 7) {
      priority = 'P1'; tier = 'B'; reasons = ['7天内活跃'];
    } else if (daysAgo <= 30) {
      priority = 'P2'; tier = 'C'; reasons = ['30天内互动'];
    } else {
      priority = 'P3'; tier = 'D'; reasons = ['超30天'];
    }

    return {
      ...c,
      daysAgo,
      isSystemMessage: isSys,
      priority,
      tier,
      reasons,
    };
  });

  classified.sort((a, b) => a.daysAgo - b.daysAgo || b.isUnread - a.isUnread);

  const ts = new Date().toISOString().replace(/[:.]/g, '-');
  const p0p1 = classified.filter((c) => c.priority === 'P0' || c.priority === 'P1');

  const output = {
    capturedAt: new Date().toISOString(),
    method: 'cdp_v4_dom_fixed',
    stats: {
      total: classified.length,
      p0: classified.filter((c) => c.priority === 'P0').length,
      p1: classified.filter((c) => c.priority === 'P1').length,
      unread: classified.filter((c) => c.isUnread).length,
      system: classified.filter((c) => c.isSystemMessage).length,
    },
    p0p1,
    all: classified,
  };

  fs.writeFileSync(path.join(DATA_DIR, `extracted_${ts}.json`), JSON.stringify(output, null, 2));
  fs.writeFileSync(path.join(DATA_DIR, `p0p1_${ts}.json`), JSON.stringify(p0p1, null, 2));

  // Quick validation self-check
  console.log('\n=== 自检 ===');
  const issues = [];

  // Check 1: no false positives
  const falseNames = ['全部', '消息', '未读', '已读', '待回复', '待跟进', 'Assistant Eva'];
  const fps = classified.filter((c) => falseNames.some((n) => c.name.includes(n)));
  if (fps.length > 0) {
    issues.push('FALSE_POSITIVE: ' + fps.map((c) => c.name).join(', '));
  }

  // Check 2: P0 items should have non-empty messages
  const p0Empty = p0p1.filter((c) => c.priority === 'P0' && (!c.message || c.message.length < 3));
  if (p0Empty.length > 0) {
    issues.push('P0_EMPTY_MSG: ' + p0Empty.map((c) => c.name).join(', '));
  }

  // Check 3: unread count matches P0-S count
  const unreadS = classified.filter((c) => c.isUnread && c.tier === 'S');
  if (unreadS.length !== output.stats.unread) {
    issues.push('UNREAD_MISMATCH: S=' + unreadS.length + ' vs unread=' + output.stats.unread);
  }

  if (issues.length > 0) {
    console.log('⚠️ 发现 ' + issues.length + ' 个问题:');
    issues.forEach((i) => console.log('  - ' + i));
  } else {
    console.log('✅ 自检通过');
  }

  console.log(`\n统计: 共${classified.length}人 | P0=${output.stats.p0} | P1=${output.stats.p1} | 未读=${output.stats.unread}`);
  console.log(`文件: extracted_${ts}.json`);

  await page.close().catch(() => {});
  await browser.close().catch(() => {});
})().catch((err) => {
  console.error('错误:', err.message);
  process.exit(1);
});

